+func TestFormatValue(t *testing.T) {
+	t.Parallel()
+
+	tests := []struct {
+		name  string
+		value interface{}
+		want  string
+	}{
+		{
+			name:  "nil",
+			value: nil,
+			want:  "",
+		},
+		{
+			name:  "string",
+			value: "hello world",
+			want:  "hello world",
+		},
+		{
+			name:  "bool true",
+			value: true,
+			want:  "true",
+		},
+		{
+			name:  "bool false",
+			value: false,
+			want:  "false",
+		},
+		{
+			name:  "int positive",
+			value: 42,
+			want:  "42",
+		},
+		{
+			name:  "int negative",
+			value: -10,
+			want:  "-10",
+		},
+		{
+			name:  "int zero",
+			value: 0,
+			want:  "0",
+		},
+		{
+			name:  "int64",
+			value: int64(9223372036854775807),
+			want:  "9223372036854775807",
+		},
+		{
+			name:  "float64 integer-like",
+			value: 42.0,
+			want:  "42",
+		},
+		{
+			name:  "float64 with decimals",
+			value: 3.14159,
+			want:  "3.14159",
+		},
+		{
+			name:  "[]byte",
+			value: []byte("byte slice"),
+			want:  "byte slice",
+		},
+		{
+			name:  "map - JSON marshaled",
+			value: map[string]string{"key": "value"},
+			want:  `{"key":"value"}`,
+		},
+		{
+			name:  "slice - JSON marshaled",
+			value: []int{1, 2, 3},
+			want:  "[1,2,3]",
+		},
+	}
+
+	for _, tt := range tests {
+		t.Run(tt.name, func(t *testing.T) {
+			t.Parallel()
+			got := formatValue(tt.value)
+			if got != tt.want {
+				t.Errorf("formatValue(%v) = %q, want %q", tt.value, got, tt.want)
+			}
+		})
+	}
+}
